(314, 51, 2, 'VOICE', '', '', NULL, 'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%61%31%64%34%61%62%33%61%61%61%30%64%30%66%34%65%32%36%30%34%62%61%36.silk', 'https://drh.likeduoduiyi.cn/homework/voice/f75aa011a96349f5b7c1cba6a05c5708.mp3', 97000, NULL, NULL, 97000, 0, 'liuyuan_config_20260601', 'liuyuan_config_20260601', '2026-06-01 17:02:46.275000', '2026-06-01 19:59:44.046000'),
(315, 52, 1, 'TEXT', '', '', '很多同学都觉得今天这节课很难，要唱高音，但您表现的很棒，今天的技巧都掌握了，我听完了你提交的作业，我马上给你点评！明天是很关键的一节课，一定要来参加！', NULL, NULL, NULL, NULL, NULL, 2000, 1, 'liuyuan_config_20260601', 'liuyuan_config_20260601', '2026-06-01 17:02:46.586000', '2026-06-01 19:59:44.046000'),
(316, 52, 2, 'VOICE', '', '', NULL, 'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%61%31%64%34%61%62%37%63%34%34%37%64%65%31%32%32%65%37%62%66%61%63%34.silk', 'https://drh.likeduoduiyi.cn/homework/voice/957e0d8192854c7ab22b163cb261fc34.mp3', 107000, NULL, NULL, 107000, 0, 'liuyuan_config_20260601', 'liuyuan_config_20260601', '2026-06-01 17:02:50.740000', '2026-06-01 19:59:44.046000'),
